import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),o={name:"changelog.md"};function l(r,e,s,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to R3 (Rusty Rules Referee) are documented here.</p><h2 id="_2-1-0-2026-04-18" tabindex="-1">[2.1.0] - 2026-04-18 <a class="header-anchor" href="#_2-1-0-2026-04-18" aria-label="Permalink to &quot;[2.1.0] - 2026-04-18&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="web-dashboard-enhancements" tabindex="-1">Web Dashboard Enhancements <a class="header-anchor" href="#web-dashboard-enhancements" aria-label="Permalink to &quot;Web Dashboard Enhancements&quot;">​</a></h4><ul><li><strong>Live Scoreboard</strong> — Real-time scoreboard with Red/Blue team grouping, scores, and ping</li><li><strong>Live Chat Panel</strong> — In-game chat messages streamed via WebSocket with team/all channel badges</li><li><strong>Vote History Panel</strong> — Track callvotes with player name, vote type, data, and timestamp</li><li><strong>Personal Notes</strong> — Per-admin notepad persisted in the database</li><li><strong>Enhanced Stats Cards</strong> — 6 stat cards: players, map, game type, uptime, warnings, total bans</li><li><strong>Quick Access Panel</strong> — One-click shortcut bar to key management pages</li><li><strong>Audit Log Page</strong> — Paginated, filterable admin action history (admin-only)</li><li><strong>Dashboard Summary API</strong> — New <code>/api/v1/stats/summary</code> endpoint</li></ul><h4 id="backend" tabindex="-1">Backend <a class="header-anchor" href="#backend" aria-label="Permalink to &quot;Backend&quot;">​</a></h4><ul><li>New database migration (004): <code>chat_messages</code>, <code>vote_history</code>, <code>admin_notes</code> tables</li><li>Storage trait extended with 7 new methods for chat, votes, notes, and summary</li><li>Chat messages persisted via chatlogger plugin</li><li>Callvotes persisted via callvote plugin</li><li>4 new API endpoints: <code>/chat</code>, <code>/votes</code>, <code>/notes</code>, <code>/audit-log</code></li><li>Players API now returns <code>score</code> and <code>ping</code> fields</li></ul><h4 id="new-plugins" tabindex="-1">New Plugins <a class="header-anchor" href="#new-plugins" aria-label="Permalink to &quot;New Plugins&quot;">​</a></h4><ul><li><strong>headshotcounter</strong> — Headshot streak tracking and announcements</li><li><strong>namechecker</strong> — Player name validation and enforcement</li><li><strong>specchecker</strong> — Spectator monitoring and enforcement</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Dashboard page redesigned with 2-column grid layout</li><li>Plugin count increased from 22 to 30</li></ul><hr><h2 id="_2-0-0-2026-04-17" tabindex="-1">[2.0.0] - 2026-04-17 <a class="header-anchor" href="#_2-0-0-2026-04-17" aria-label="Permalink to &quot;[2.0.0] - 2026-04-17&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Complete rewrite in Rust (from the original Python B3 bot)</li><li>Async runtime powered by tokio</li><li>Urban Terror 4.3 log parser with 18 regex patterns and 40+ weapon mappings</li><li>22 plugins at launch</li><li>Plugin trait system with lifecycle management and event dispatching</li><li>Event system with 60+ event types</li><li>SQLite and MySQL database backends with automatic migrations</li><li>UDP RCON client for Quake 3 engine protocol</li><li>Async log file tailer with rotation detection</li><li>TOML-based configuration</li><li>XLRstats extended player statistics</li><li>SvelteKit 2 web dashboard with Tailwind CSS</li><li>JWT authentication and role-based access control</li><li>WebSocket real-time event streaming</li><li>REST API with 20+ endpoints</li></ul>',16)])])}const u=a(o,[["render",l]]);export{m as __pageData,u as default};
